use vstd::prelude::*;

verus! {

spec fn is_max_index(idx: int, a: &Seq<i32>, len: int) -> bool {
    &&& 0 <= idx < len
    &&& forall|j: int| 0 <= j < len ==> a[j] <= a[idx]
}

fn max(a: &Vec<i32>) -> (x: usize)
    requires
        a.len() > 0,
    ensures
        is_max_index(x as int, &a@, a.len() as int),
{
    let mut x: usize = 0;
    let mut y: usize = a.len() - 1;
    let mut m: usize = y;

    while x != y
        invariant
            0 <= x <= y < a.len(),
            is_max_index(m as int, &a@, a.len() as int),
        decreases
            y - x
    {
        if a[x] <= a[y] {
            x = x + 1;
            m = y;
        } else {
            y = y - 1;
            m = x;
        }
    }

    x
}

