verus! {

fn tangent(r: Vec<u64>, x: Vec<u64>) -> (b: bool)
    ensures
        b == (exists|k: int| 0 <= k < r.len() && (exists|l: int| 0 <= l < x.len() && r[k] == x[l])),
{
    let mut temp_b = false;
    let mut k: usize = 0;
    while k < r.len() && !temp_b
        invariant
            0 <= k <= r.len(),
            temp_b == (exists|i: int| 0 <= i < k && (exists|j: int| 0 <= j < x.len() && r[i] == x[j])),
        decreases
            r.len() - k
    {
        let mut l: usize = 0;
        let mut tangent_missing = false;
        while l < x.len() && !tangent_missing && k < r.len()
            invariant
                0 <= l <= x.len(),
                tangent_missing == (l == x.len() && (forall|j: int| 0 <= j < x.len() ==> r[k] < x[j])),
                temp_b == (exists|i: int| 0 <= i < k && (exists|j: int| 0 <= j < x.len() && r[i] == x[j])),
                k < r.len(),
            decreases
                x.len() - l
        {
            if r[k] == x[l] {
                temp_b = true;
            }
            if l == x.len() - 1 && r[k] < x[l] {
                tangent_missing = true;
            }
            l = l + 1;
        }
        k = k + 1;
    }
    temp_b
}

fn main() {
    // Write a function in Rust to check whether any value in a sequence exists in a sequence or not.

    assert!(!tangent(vec![1, 2, 3, 4, 5], vec![6, 7, 8, 9]));
    assert!(!tangent(vec![1, 2, 3], vec![4, 5, 6]));
    assert!(tangent(vec![1, 4, 5], vec![1, 4, 5]));
