verus! {

fn reverse(a: Vec<char>) -> (b: Vec<char>)
    requires
        a.len() > 0,
    ensures
        b.len() == old(a).len(),
        forall|i: int| 0 <= i < old(a).len() ==> b[i] == old(a)[old(a).len() - 1 - i],
{
    let mut b: Vec<char> = Vec::new();
    let mut k: usize = 0;

    while k < a.len()
        invariant
            0 <= k <= a.len(),
            b.len() == k,
            forall|i: int| 0 <= i < k ==> b[i] == a[a.len() - 1 - i],
        decreases
            a.len() - k
    {
        b.push(a[a.len() - 1 - k]);
        k = k + 1;
    }

    b
}

}

