fn absx(x: Vec<i32>) -> (y: Vec<i32>)
    requires
        forall|i: int| 0 <= i < x.len() ==> x[i] != i32::MIN,
    ensures
        y.len() == x.len(),
        forall|i: int| 0 <= i < x.len() ==> {
            if x[i] >= 0 { y[i] == x[i] } else { y[i] == -x[i] }
        }
{
    let mut y: Vec<i32> = Vec::new();
    let mut j: usize = 0;

    while j < x.len()
        invariant
            0 <= j <= x.len(),
            y.len() == j,
            forall|i: int| 0 <= i < j ==> {
                if x[i] >= 0 { y[i] == x[i] } else { y[i] == -x[i] }
            },
            forall|i: int| 0 <= i < x.len() ==> x[i] != i32::MIN
        decreases
            x.len() - j
    {
        if x[j] < 0 {
            assert(x[j] != i32::MIN);
            y.push(-x[j]);
        } else {
            y.push(x[j]);
        }
        j += 1;
    }
    y
}

